class Solution:
    def countCharacters(self, words, chars):
        from collections import Counter
        pool = Counter(chars)
        total = 0
        for w in words:
            wc = Counter(w)
            if all(pool[ch] >= cnt for ch, cnt in wc.items()):
                total += len(w)
        return total

