var countCharacters = function(words, chars) {
    const pool = {};
    for (const c of chars) pool[c] = (pool[c] || 0) + 1;
    let total = 0;
    for (const w of words) {
        const wc = {};
        for (const c of w) wc[c] = (wc[c] || 0) + 1;
        let ok = true;
        for (const c in wc) {
            if ((pool[c] || 0) < wc[c]) { ok = false; break; }
        }
        if (ok) total += w.length;
    }
    return total;
};
